				dispatch.Assigns[newAssignIdx].GenRoute()
				if dispatch.Assigns[newAssignIdx].Cost >= 0 {
					delta := dispatch.Assigns[newAssignIdx].Cost - savedCostNew
					if delta < bestCandidate.costDelta {
						bestCandidate = candidate{assignIdx: newAssignIdx, costDelta: delta, newAssign: true}
						foundFeasible = true
					}
				}
				dispatch.Assigns[newAssignIdx].RemoveShip(id)
				dispatch.Assigns[newAssignIdx].StationsLen = savedStationsLenNew
				dispatch.Assigns[newAssignIdx].GenRoute()
				dispatch.Assigns[newAssignIdx].Cost = savedCostNew
			}
		}
		if foundFeasible {
			chosenIdx := bestCandidate.assignIdx
			dispatch.Assigns[chosenIdx].AddShip(id, ori, des)
			dispatch.Assigns[chosenIdx].GenRoute()
			if bestCandidate.newAssign {
				dispatch.AssignsLen++
			}
		} else {
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx < MAXASSIGNS {
				dispatch.Assigns[fallbackIdx].AddShip(id, ori, des)
				dispatch.Assigns[fallbackIdx].GenRoute()
				dispatch.AssignsLen++
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch
}

